          ...log,
        },
      ],
      lastActivityAt: Date.now(),
    }));
  },
  clearOrchestrationLogs: () => set({ orchestrationLogs: [] }),

  orchestrationStartedAt: null,
  lastActivityAt: null,

  worktreeEntries: new Map(),
  setWorktreeEntries: (entries) => set({ worktreeEntries: entries }),

  clearSession: () => {
    set({
