      agentContexts: new Map(),
      activePlan: null,
      pendingQuestion: null,
      rateLimitAlert: null,
      decomposedTasks: [],
      orchestrationLogs: [],
      orchestrationPhase: 'idle',
      orchestrationStartedAt: null,
      lastActivityAt: null,
      worktreeEntries: new Map(),
    });
  },
}));

