import { useTaskStore, type ToolName, type TaskStatus, type WorktreeReviewEntry } from '../../stores/taskStore';
import { emitOrchestrationNotification } from '../../stores/notificationStore';
import { asToolName } from '../../lib/agents';

/* ── Structured orchestrator event handler ───────────────── */

export type OrchEvent =
  | { type: 'phase_changed'; phase: string; detail?: string; task_count?: number; wave_count?: number; plan_id?: string; master_agent?: string }
  | { type: 'task_assigned'; agent: string; description: string; prompt?: string; dag_id?: string }
  | { type: 'task_completed'; dag_id?: string; summary?: string; exit_code?: number }
  | { type: 'task_failed'; dag_id?: string; summary?: string; exit_code?: number; agent?: string; failure_reason?: string }
  | { type: 'decomposition_failed'; error: string }
  | { type: 'wave_progress'; current: number; total: number }
  | { type: 'task_skipped'; dag_id: string; reason: string }
  | { type: 'task_retrying'; dag_id: string; attempt: number; max_retries: number }
  | { type: 'task_fallback'; dag_id: string; from_agent: string; to_agent: string }
  | { type: 'rate_limited'; dag_id: string; wait_seconds: number }
  | { type: 'rate_limit_action_needed'; agent: string; remaining_tasks: Array<{ dag_id: string; description: string; prompt: string }>; available_agents: string[]; plan_id: string; resets_at?: string }
  | { type: 'master_timeout'; timeout_minutes: number }
  | { type: 'worker_timeout'; timeout_minutes: number }
  | { type: 'review_timeout'; timeout_minutes: number }
  | { type: 'question'; agent: string; content: string; plan_id?: string }
  | { type: 'question_answered'; agent: string }
  | { type: 'dispatch_error'; dag_id: string; error: string }
  | { type: 'worker_output'; dag_id: string; line: string }
  | { type: 'worker_started'; dag_id: string; process_id: string }
  | { type: 'diffs_ready'; diffs: Array<{ dag_id: string; branch_name: string; file_count: number; additions: number; deletions: number }> }
  | { type: 'info'; message: string };

const lastOutputUpdateByDag = new Map<string, number>();

export function handleOrchEvent(
  ev: OrchEvent,
  masterAgent: ToolName,
  dagToFrontendId: Map<string, string>,
  dagCounter: number,
) {
  const store = useTaskStore.getState();
  type LogLevel = 'info' | 'success' | 'warn' | 'cmd' | 'error';
  const log = (level: LogLevel, message: string) =>
    store.addOrchestrationLog({ agent: masterAgent, level, message });

  switch (ev.type) {
    case 'phase_changed': {
      const phase = ev.phase;
      if (phase === 'decomposing') {
        lastOutputUpdateByDag.clear();
        store.setOrchestrationPhase('decomposing');
        // Set activePlan early from enriched event so it's available before awaiting_approval
        if (ev.plan_id) {
          store.setActivePlan({
            task_id: ev.plan_id,
            master_agent: ev.master_agent ? asToolName(ev.master_agent) : masterAgent,
            master_process_id: null,
          });
        }
        log('cmd', `Phase 1: ${ev.detail || 'Decomposing'}`);
      } else if (phase === 'awaiting_approval') {
        store.setOrchestrationPhase('awaiting_approval');
        log('info', `${ev.task_count} sub-tasks ready for approval`);
      } else if (phase === 'executing') {
        store.setOrchestrationPhase('executing');
        // Move pending worker tasks to 'waiting' (queued) — they'll transition
        // to 'running' when their worker_started event arrives from the backend
        for (const [id, task] of store.tasks) {
          if (task.status === 'pending' && task.role === 'worker') {
            store.updateTaskStatus(id, 'waiting');
          }
        }
        log('cmd', `Phase 2: Executing ${ev.task_count ?? ''} sub-tasks in ${ev.wave_count ?? ''} wave(s)`);
      } else if (phase === 'reviewing') {
        store.setOrchestrationPhase('reviewing');
        log('cmd', `Phase 3: ${ev.detail || 'Reviewing'}`);
      } else if (phase === 'completed') {
        store.setOrchestrationPhase('completed');
        // Mark master task as completed
        const currentTasks = useTaskStore.getState().tasks;
        for (const [id, t] of currentTasks) {
          if (t.role === 'master' && t.status !== 'completed') {
            store.updateTaskStatus(id, 'completed');
            break;
          }
        }
        log('success', 'Orchestration completed');
      }
      break;
    }

    case 'task_assigned': {
      const agent = ev.agent;
      const desc = ev.description;
      const prompt = ev.prompt || desc; // Full prompt from backend, fallback to description
      const subId = crypto.randomUUID();
      const phase2Already = store.orchestrationPhase === 'executing';
      store.addTask({
        taskId: subId,
        prompt,
        toolName: asToolName(agent),
        status: phase2Already ? 'running' : 'pending',
        description: desc.length > 60 ? desc.slice(0, 57) + '...' : desc,
        startedAt: phase2Already ? Date.now() : null,
        dependsOn: null,
        role: 'worker',
      });
      dagToFrontendId.set(ev.dag_id ?? `t${dagCounter + 1}`, subId);
      log('info', `Assigned to ${agent}: ${desc}`);
      break;
    }

    case 'task_completed':
    case 'task_failed': {
      if (!ev.dag_id) {
        console.warn(`${ev.type} received without dag_id — cannot match to frontend task`);
      }
      const status: TaskStatus = ev.type === 'task_completed' ? 'completed' : 'failed';
      const targetId = ev.dag_id ? dagToFrontendId.get(ev.dag_id) : undefined;
      if (!targetId && ev.dag_id) {
        console.warn(`Unmatched dag_id in ${ev.type}: ${ev.dag_id}`);
      }
      if (targetId) {
        store.updateTaskStatus(targetId, status);
      }
      const summary = ev.summary || '';
      // Store failure detail on the task for inspection in TaskDetail
      if (ev.type === 'task_failed' && targetId && summary) {
        store.updateTaskResult(targetId, summary.slice(0, 500));
      }
      if (ev.type === 'task_failed') {
        // Log detailed failure info — agent, exit code, failure reason, and full summary
        const agent = (ev as { agent?: string }).agent || 'unknown';
        const reason = (ev as { failure_reason?: string }).failure_reason || '';
        log('error', `[${agent}] Failed (exit ${ev.exit_code})`);
        if (reason) log('error', `Failure reason: ${reason}`);
        if (summary) log('error', `Output:\n${summary.slice(0, 500)}`);
      } else {
        log('success', `Completed (exit ${ev.exit_code}): ${summary}`);
      }
      // Emit notification for task completion/failure
      emitOrchestrationNotification(
        ev.type === 'task_completed' ? 'success' : 'error',
        ev.type === 'task_completed' ? 'Task Completed' : 'Task Failed',
        summary.slice(0, 100) || undefined,
        targetId ? { label: 'View', taskId: targetId } : undefined,
      );
      break;
    }

    case 'wave_progress': {
      log('info', `\u27D0 Wave ${ev.current}/${ev.total}`);
      break;
    }

    case 'task_skipped': {
      const dagId = ev.dag_id;
      const frontendId = dagToFrontendId.get(dagId);
      if (frontendId) {
        store.updateTaskStatus(frontendId, 'blocked');
      }
      log('warn', `Skipping ${dagId}: ${ev.reason}`);
      break;
    }

    case 'task_retrying': {
      const dagId = ev.dag_id;
      const frontendId = dagToFrontendId.get(dagId);
      if (frontendId) {
        store.updateTaskStatus(frontendId, 'retrying');
      }
      log('info', `Retrying ${dagId} (attempt ${ev.attempt}/${ev.max_retries})`);
      break;
    }

    case 'task_fallback': {
      const dagId = ev.dag_id;
      const newAgent = ev.to_agent;
      const frontendId = dagToFrontendId.get(dagId);
      if (frontendId) {
        const task = store.tasks.get(frontendId);
        if (task) {
          const newTasks = new Map(store.tasks);
          newTasks.set(frontendId, { ...task, toolName: asToolName(newAgent), status: 'falling_back' });
          useTaskStore.setState({ tasks: newTasks });
        }
      }
      log('info', `Falling back: ${dagId} reassigned from ${ev.from_agent} to ${newAgent}`);
      break;
    }

    case 'rate_limited': {
      log('warn', `Rate limited on ${ev.dag_id} — waiting ${ev.wait_seconds}s`);
      break;
    }

    case 'rate_limit_action_needed': {
      const agent = asToolName(ev.agent);
      log('error', `${ev.agent} rate limit reached! ${ev.remaining_tasks.length} tasks remaining.`);
      store.setRateLimitAlert({
        agent,
        remainingTasks: ev.remaining_tasks.map(t => ({ dagId: t.dag_id, description: t.description, prompt: t.prompt })),
        availableAgents: ev.available_agents.map(a => asToolName(a)),
        planId: ev.plan_id,
        resetsAt: ev.resets_at,
      });
      emitOrchestrationNotification(
        'warning',
        `${ev.agent} Rate Limit Reached`,
        `${ev.remaining_tasks.length} tasks need reassignment`,
        { label: 'Review' },
      );
      break;
    }

    case 'master_timeout':
    case 'worker_timeout':
    case 'review_timeout': {
      log('error', `${ev.type.replace('_', ' ')} after ${ev.timeout_minutes} minutes`);
      break;
    }

    case 'question': {
      log('info', `${ev.agent} asks: ${ev.content}`);
      // Set pending question so the UI shows the answer prompt
      if (ev.plan_id) {
        store.setPendingQuestion({
          questionId: `q-${Date.now()}`,
          sourceAgent: ev.agent,
          content: ev.content,
          planId: ev.plan_id,
        });
      }
      // Notify user — especially useful when app is in background
      emitOrchestrationNotification(
        'warning',
        `${ev.agent} has a question`,
        String(ev.content).slice(0, 100),
        { label: 'Answer' },
      );
      break;
    }

    case 'question_answered': {
      log('info', `Master answered ${ev.agent}'s question`);
      store.setPendingQuestion(null);
      break;
    }

    case 'dispatch_error': {
      log('error', `Dispatch failed for ${ev.dag_id}: ${ev.error}`);
      break;
    }

    case 'info': {
      log('info', ev.message);
      break;
    }

    case 'worker_output': {
      const frontendId = dagToFrontendId.get(ev.dag_id);
      if (frontendId) {
        const now = Date.now();
        const lastUpdate = lastOutputUpdateByDag.get(ev.dag_id) ?? 0;
        if (now - lastUpdate > 500) {
          lastOutputUpdateByDag.set(ev.dag_id, now);
          store.updateTaskOutputLine(frontendId, ev.line);
        }
      }
      break;
    }

    case 'worker_started': {
      const frontendId = dagToFrontendId.get(ev.dag_id);
      if (frontendId) {
        store.updateTaskStatus(frontendId, 'running');
      }
      break;
    }

    case 'diffs_ready': {
      const entries = new Map<string, WorktreeReviewEntry>();
      for (const d of ev.diffs) {
        entries.set(d.dag_id, {
          dagId: d.dag_id,
          branchName: d.branch_name,
          fileCount: d.file_count,
          additions: d.additions,
          deletions: d.deletions,
        });
      }
      store.setWorktreeEntries(entries);
      log('info', `Diffs ready: ${ev.diffs.length} worktrees`);
      break;
    }

    case 'decomposition_failed': {
      log('error', ev.error);
      // Use fresh state to find the master task
      const currentTasks = useTaskStore.getState().tasks;
      for (const [id, t] of currentTasks) {
        if (t.role === 'master') {
          store.updateTaskResult(id, ev.error);
          break;
        }
      }
      break;
    }
  }
}

import { useState, useCallback, useEffect, useRef } from 'react';
import { commands } from '../bindings';
import type { ConflictReport, WorktreeDiffReport } from '../bindings';
import { useTaskStore } from '../stores/taskStore';

/**
 * React hook for managing git worktrees via IPC.
 *
 * Wraps all 5 worktree IPC commands (create, list, check conflicts, merge, cleanup)
 * and provides reactive state for worktree list, conflict reports, and loading status.
 */
export function useWorktree(projectDir: string) {
  const [worktrees, setWorktrees] = useState<string[]>([]);
  const [conflicts, setConflicts] = useState<ConflictReport | null>(null);
  const [diffReport, setDiffReport] = useState<WorktreeDiffReport | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const refreshWorktrees = useCallback(async () => {
    if (!projectDir) return;
    setLoading(true);
    setError(null);
    try {
      const result = await commands.listWorktrees(projectDir);
      if (result.status === 'ok') {
        setWorktrees(result.data);
      } else {
        setError(result.error);
      }
    } catch (err) {
      setError('Failed to list worktrees');
    } finally {
      setLoading(false);
    }
  }, [projectDir]);

  const checkConflicts = useCallback(
    async (branchA: string, branchB: string) => {
      if (!projectDir) return;
      setLoading(true);
      setError(null);
      try {
        const result = await commands.checkWorktreeConflicts(projectDir, branchA, branchB);
        if (result.status === 'ok') {
          setConflicts(result.data);
        } else {
          setError(result.error);
        }
      } catch (err) {
        setError('Failed to check conflicts');
      } finally {
        setLoading(false);
      }
    },
    [projectDir],
  );

  const mergeWorktree = useCallback(
    async (branchName: string): Promise<boolean> => {
      if (!projectDir) return false;
      setLoading(true);
      setError(null);
      try {
        const result = await commands.mergeWorktree(projectDir, branchName, null);
        if (result.status === 'ok') {
          setConflicts(null);
          await refreshWorktrees();
          return true;
        } else {
          setError(result.error);
          return false;
        }
      } catch (err) {
        setError('Failed to merge worktree');
        return false;
      } finally {
        setLoading(false);
      }
    },
    [projectDir, refreshWorktrees],
  );

  const getWorktreeDiff = useCallback(
    async (branchName: string): Promise<WorktreeDiffReport | null> => {
      if (!projectDir) return null;
      setLoading(true);
      setError(null);
      try {
        const result = await commands.getWorktreeDiff(projectDir, branchName);
        if (result.status === 'ok') {
          setDiffReport(result.data);
          return result.data;
        } else {
          setError(result.error);
          return null;
        }
      } catch (err) {
        setError('Failed to get worktree diff');
        return null;
      } finally {
        setLoading(false);
      }
    },
    [projectDir],
  );

  const selectiveMerge = useCallback(
    async (branchName: string, acceptedFiles: string[]): Promise<boolean> => {
      if (!projectDir) return false;
      setLoading(true);
      setError(null);
      try {
        const result = await commands.mergeWorktree(projectDir, branchName, acceptedFiles);
        if (result.status === 'ok') {
          setConflicts(null);
          setDiffReport(null);
          await refreshWorktrees();
          return true;
        } else {
          setError(result.error);
          return false;
        }
      } catch (err) {
        setError('Failed to merge selected files');
        return false;
      } finally {
        setLoading(false);
      }
    },
    [projectDir, refreshWorktrees],
  );

  const cleanupWorktrees = useCallback(async () => {
    if (!projectDir) return;
    setLoading(true);
    setError(null);
    try {
      const result = await commands.cleanupWorktrees(projectDir);
      if (result.status === 'ok') {
        await refreshWorktrees();
      } else {
        setError(result.error);
      }
    } catch (err) {
      setError('Failed to cleanup worktrees');
    } finally {
      setLoading(false);
    }
  }, [projectDir, refreshWorktrees]);

  // Refresh worktree list on mount and when projectDir changes
  useEffect(() => {
    if (projectDir) {
      refreshWorktrees();
    }
  }, [projectDir, refreshWorktrees]);

  // Refresh when any task transitions to 'running' (worktree just created)
  const prevTaskStatuses = useRef<Map<string, string>>(new Map());
  const tasks = useTaskStore((s) => s.tasks);
  useEffect(() => {
    let shouldRefresh = false;
    const currentStatuses = new Map<string, string>();
    for (const [id, t] of tasks.entries()) {
      currentStatuses.set(id, t.status);
      const prev = prevTaskStatuses.current.get(id);
      if (t.status === 'running' && prev !== 'running') {
        shouldRefresh = true;
      }
    }
    prevTaskStatuses.current = currentStatuses;
    if (shouldRefresh && projectDir) {
      refreshWorktrees();
    }
  }, [tasks, projectDir, refreshWorktrees]);

  return {
    worktrees,
    conflicts,
    diffReport,
    loading,
    error,
    refreshWorktrees,
    checkConflicts,
    mergeWorktree,
    getWorktreeDiff,
    selectiveMerge,
    cleanupWorktrees,
  };
}

import { useState, useEffect, useMemo } from 'react';
import { ask } from '@tauri-apps/plugin-dialog';
import { useWorktree } from '../../hooks/useWorktree';
import { FileDiffView } from './FileDiffView';
import type { FileDiff } from '../../bindings';

interface DiffReviewProps {
  projectDir: string;
  branchName: string;
  taskId: string;
  onClose: (action: 'merged' | 'discarded') => void;
}

/** Status icon and color for a file diff entry. */
function statusIcon(status: string): { icon: string; color: string } {
  switch (status) {
    case 'added':
      return { icon: '+', color: 'text-green-400' };
    case 'deleted':
      return { icon: 'D', color: 'text-red-400' };
    case 'renamed':
      return { icon: 'R', color: 'text-yellow-400' };
    case 'modified':
    default:
      return { icon: 'M', color: 'text-blue-400' };
  }
}

/**
 * Diff review panel with file list sidebar and unified diff viewer.
 *
 * Allows users to accept/reject individual files before merging.
 * No auto-merge -- every merge requires explicit user action.
 */
export function DiffReview({ projectDir, branchName, taskId: _taskId, onClose }: DiffReviewProps) {
  const { diffReport, loading, error, getWorktreeDiff, selectiveMerge, cleanupWorktrees } =
    useWorktree(projectDir);

  const [acceptedFiles, setAcceptedFiles] = useState<Set<string>>(new Set());
  const [selectedFile, setSelectedFile] = useState<string | null>(null);
  const [merging, setMerging] = useState(false);

  // Fetch diff on mount
  useEffect(() => {
    getWorktreeDiff(branchName);
  }, [branchName, getWorktreeDiff]);

  // Initialize acceptedFiles when diffReport arrives (default: accept all)
  useEffect(() => {
    if (diffReport?.files) {
      setAcceptedFiles(new Set(diffReport.files.map((f) => f.path)));
      if (diffReport.files.length > 0 && !selectedFile) {
        setSelectedFile(diffReport.files[0].path);
      }
    }
  }, [diffReport]); // eslint-disable-line react-hooks/exhaustive-deps

  const files = diffReport?.files ?? [];

  const selectedDiff: FileDiff | undefined = useMemo(
    () => files.find((f) => f.path === selectedFile),
    [files, selectedFile],
  );

  const acceptedCount = acceptedFiles.size;
  const rejectedCount = files.length - acceptedCount;

  const toggleFile = (path: string) => {
    setAcceptedFiles((prev) => {
      const next = new Set(prev);
      if (next.has(path)) {
        next.delete(path);
      } else {
        next.add(path);
      }
      return next;
    });
  };

  const selectAll = () => {
    setAcceptedFiles(new Set(files.map((f) => f.path)));
  };

  const deselectAll = () => {
    setAcceptedFiles(new Set());
  };

  const handleMerge = async () => {
    if (acceptedFiles.size === 0) {
      const discardAll = await ask(
        'No files are accepted. Discard all changes from this task?',
        { title: 'Discard Changes', kind: 'warning' },
      );
      if (!discardAll) return;
      await cleanupWorktrees();
      onClose('discarded');
      return;
    }

    const mergeMsg = rejectedCount > 0
      ? `Merge ${acceptedCount} file${acceptedCount !== 1 ? 's' : ''}? ${rejectedCount} file${rejectedCount !== 1 ? 's' : ''} will be discarded.`
      : `Merge ${acceptedCount} file${acceptedCount !== 1 ? 's' : ''}?`;
    const confirmed = await ask(mergeMsg, { title: 'Confirm Merge', kind: 'info' });
    if (!confirmed) return;

    setMerging(true);
    try {
      const success = await selectiveMerge(branchName, Array.from(acceptedFiles));
      onClose(success ? 'merged' : 'discarded');
    } catch {
      // selectiveMerge threw — merge genuinely failed
      onClose('discarded');
    } finally {
      setMerging(false);
    }
  };

  const handleDiscard = async () => {
    const confirmed = await ask(
      'Discard all changes from this task?',
      { title: 'Discard All Changes', kind: 'warning' },
    );
    if (!confirmed) return;

    setMerging(true);
    try {
      // Note: cleanupWorktrees only prunes stale/orphaned worktrees via cleanup_stale_worktrees().
      // The active worktree for this branch may persist until the next cleanup cycle or app restart.
      // A proper fix would expose remove_worktree(branchName) as a Tauri command.
      await cleanupWorktrees();
      onClose('discarded');
    } finally {
      setMerging(false);
    }
  };

  // Loading state
  if (loading && !diffReport) {
    return (
      <div className="flex items-center justify-center h-full text-zinc-400">
        <div className="flex items-center gap-2">
          <div className="w-4 h-4 border-2 border-zinc-500 border-t-zinc-200 rounded-full animate-spin" />
          <span className="text-sm">Loading diff...</span>
        </div>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-full gap-3 text-zinc-400">
        <p className="text-sm text-red-400">{error}</p>
        <button
          onClick={() => getWorktreeDiff(branchName)}
          className="px-3 py-1.5 text-xs rounded bg-zinc-700 hover:bg-zinc-600 text-zinc-200 transition-colors"
        >
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-zinc-950">
      {/* Header */}
      <div className="shrink-0 flex items-center justify-between px-4 py-2 border-b border-zinc-800 bg-zinc-900/60">
        <div className="flex items-center gap-2">
          <span className="text-sm font-medium text-zinc-200">Review Changes</span>
          <span className="text-xs text-zinc-500">
            {diffReport?.branch_name} &rarr; {diffReport?.default_branch}
          </span>
        </div>
        <div className="flex items-center gap-2 text-xs text-zinc-400">
          <span className="text-green-400">+{diffReport?.total_additions ?? 0}</span>
          <span className="text-red-400">-{diffReport?.total_deletions ?? 0}</span>
        </div>
      </div>

      {/* Main content */}
      <div className="flex flex-1 min-h-0">
        {/* File list sidebar */}
        <div className="w-72 shrink-0 flex flex-col border-r border-zinc-800 bg-zinc-900/40">
          {/* Select all / deselect all */}
          <div className="shrink-0 flex items-center gap-2 px-3 py-2 border-b border-zinc-800">
            <button
              onClick={selectAll}
              className="text-xs text-zinc-400 hover:text-zinc-200 transition-colors"
            >
              Select All
            </button>
            <span className="text-zinc-700">|</span>
            <button
              onClick={deselectAll}
              className="text-xs text-zinc-400 hover:text-zinc-200 transition-colors"
            >
              Deselect All
            </button>
            <span className="ml-auto text-xs text-zinc-500">
              {files.length} file{files.length !== 1 ? 's' : ''}
            </span>
          </div>

          {/* File list */}
          <div className="flex-1 overflow-y-auto">
            {files.map((file) => {
              const { icon, color } = statusIcon(file.status);
              const isSelected = selectedFile === file.path;
              const isAccepted = acceptedFiles.has(file.path);

              return (
                <div
                  key={file.path}
                  className={`flex items-center gap-2 px-3 py-1.5 cursor-pointer text-xs transition-colors ${
                    isSelected
                      ? 'bg-zinc-800 text-zinc-100'
                      : 'text-zinc-400 hover:bg-zinc-800/50 hover:text-zinc-200'
                  }`}
                  onClick={() => setSelectedFile(file.path)}
                >
                  <input
                    type="checkbox"
                    checked={isAccepted}
                    onChange={(e) => {
                      e.stopPropagation();
                      toggleFile(file.path);
                    }}
                    onClick={(e) => e.stopPropagation()}
                    className="shrink-0 rounded border-zinc-600 bg-zinc-800 text-blue-500 focus:ring-0 focus:ring-offset-0"
                  />
                  <span className={`shrink-0 font-mono font-bold ${color}`}>{icon}</span>
                  <span className="truncate flex-1" title={file.path}>
                    {file.path}
                  </span>
                  <span className="shrink-0 text-green-500">+{file.additions}</span>
                  <span className="shrink-0 text-red-500">-{file.deletions}</span>
                </div>
              );
            })}
          </div>
        </div>

        {/* Diff viewer */}
        <div className="flex-1 min-w-0">
          {selectedDiff ? (
            <FileDiffView patch={selectedDiff.patch} />
          ) : (
            <div className="flex items-center justify-center h-full text-zinc-500 text-sm">
              Select a file to view its diff
            </div>
          )}
        </div>
      </div>

      {/* Bottom bar - only shown when there are files to review */}
      {files.length > 0 && (
        <div className="shrink-0 flex items-center justify-between px-4 py-2.5 border-t border-zinc-800 bg-zinc-900/60">
          <span className="text-xs text-zinc-400">
            {acceptedCount} file{acceptedCount !== 1 ? 's' : ''} accepted
            {rejectedCount > 0 && (
              <span className="text-zinc-500">
                , {rejectedCount} rejected
              </span>
            )}
          </span>
          <div className="flex items-center gap-2">
            <button
              onClick={handleDiscard}
              disabled={merging}
              className="px-3 py-1.5 text-xs rounded bg-zinc-800 text-red-400 hover:bg-zinc-700 hover:text-red-300 disabled:opacity-50 transition-colors"
            >
              Discard All
            </button>
            <button
              onClick={handleMerge}
              disabled={merging}
              className="px-3 py-1.5 text-xs rounded bg-blue-600 text-white hover:bg-blue-500 disabled:opacity-50 transition-colors"
            >
              {merging ? 'Merging...' : 'Merge Accepted'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

interface FileDiffViewProps {
  patch: string;
}

/**
 * Renders a unified diff patch with line-level coloring.
 *
 * Line coloring by prefix:
 * - `+` lines: green text on green bg/20
 * - `-` lines: red text on red bg/20
 * - `@@` lines: cyan
 * - `diff`, `index`, `---`, `+++` header lines: muted zinc-500
 * - Context lines: zinc-300
 */
export function FileDiffView({ patch }: FileDiffViewProps) {
  if (!patch || patch.trim().length === 0) {
    return (
      <div className="flex items-center justify-center h-full text-zinc-500 text-sm">
        No diff available
      </div>
    );
  }

  const lines = patch.split('\n');

  return (
    <div className="overflow-auto h-full font-mono text-xs leading-5">
      {lines.map((line, i) => {
        let className = 'px-3 whitespace-pre text-zinc-300';

        // Check multi-char header prefixes first (before single-char +/-)
        if (
          line.startsWith('diff ') ||
          line.startsWith('index ') ||
          line.startsWith('--- ') ||
          line.startsWith('+++ ')
        ) {
          className = 'px-3 whitespace-pre text-zinc-500';
        } else if (line.startsWith('@@')) {
          className = 'px-3 whitespace-pre text-cyan-400';
        } else if (line.startsWith('+')) {
          className = 'px-3 whitespace-pre text-green-400 bg-green-900/20';
        } else if (line.startsWith('-')) {
          className = 'px-3 whitespace-pre text-red-400 bg-red-900/20';
        }

        return (
          <div key={i} className={className}>
            {line}
          </div>
        );
      })}
    </div>
  );
}

